/**
 * /agent command handler ‚Äî hot-swap between ACP CLI backends
 * (Kiro / Claude Code / Codex) with conversation handoff.
 *
 * /agent          ‚Üí show current backend + available list
 * /agent <name>   ‚Üí archive current session ‚Üí spawn target CLI ‚Üí new session
 *                   with the handoff archive injected into its preamble
 *
 * Direct-API switching stays on /model ‚Äî /agent Êèõ‰∫∫ÔºàCLI subprocessÔºâÔºå
 * /model ÊèõËÖ¶ÔºàAPI endpointÔºâ„ÄÇ
 */
import { Context } from "grammy";
import { config } from "../config.js";
import {
  acpProvidersConfigPath,
  loadAcpProviders,
  DEFAULT_BACKEND_KEY,
} from "../acp-providers.js";
import { deps } from "./deps.js";

export async function handleAgent(ctx: Context): Promise<void> {
  const { isAllowed, sessions } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat?.id;
  const userId = ctx.from?.id;
  if (!chatId) return;

  const arg = (typeof ctx.match === "string" ? ctx.match : "").trim().toLowerCase();
  const backends = loadAcpProviders();
  const session = sessions.peek(chatId);
  const isEnvFallbackOnly =
    Object.keys(backends).length === 1 && backends[DEFAULT_BACKEND_KEY] !== undefined;

  // No argument: show current backend + available list.
  if (!arg) {
    const current = describeCurrent(session?.activeProvider, session?.acpBackend);
    const lines = [
      `ü§ñ Áï∂Ââç agentÔºö${current}`,
      "",
      "ÂèØÁî® agentÔºö",
      ...Object.values(backends).map((b) => {
        const marker = session?.activeProvider === "acp" && session?.acpBackend === b.key ? " ‚Üê Áï∂Ââç" : "";
        const pin = b.model ? `Ôºåpin ${b.model}${b.effort ? `/${b.effort}` : ""}` : "";
        return `‚Ä¢ \`${b.key}\` ‚Äî ${b.label}Ôºà${b.command} ${b.args.join(" ")}${pin}Ôºâ${marker}`;
      }),
      "",
      "Áî®Ê≥ïÔºö`/agent <ÂêçÁ®±>` ÂàáÊèõÔºàËá™Âãï‰∫§Êé•Â∞çË©±ÊëòË¶ÅÔºå‰∏çÊéâË®òÊÜ∂Ôºâ",
      "Âàá Direct API Ë´ãÁî® /model„ÄÇ",
    ];
    if (isEnvFallbackOnly) {
      lines.push(
        "",
        `‚öÝÔ∏è Â∞öÊú™Âª∫Á´ã backend Ë®≠ÂÆöÊ™îÔºåÁõÆÂâçÂè™Êúâ .env ÈÝêË®≠ agent„ÄÇ`,
        `Âª∫Á´ã ${acpProvidersConfigPath()} ÂæåÂç≥ÂèØÂ§ö agent ÂàáÊèõ„ÄÇ`,
      );
    }
    await ctx.reply(lines.join("\n"), { parse_mode: "Markdown" });
    return;
  }

  const def = backends[arg];
  if (!def) {
    await ctx.reply(
      `‚ùå Êú™Áü• agent "${arg}"„ÄÇÂèØÁî®Ôºö${Object.keys(backends).map((k) => `\`${k}\``).join("„ÄÅ")}`,
      { parse_mode: "Markdown" },
    );
    return;
  }

  if (session?.activeProvider === "acp" && session.acpBackend === arg) {
    await ctx.reply(`Â∑≤Á∂ìÂú®‰ΩøÁî® ${def.label} ‰∫Ü„ÄÇ`);
    return;
  }

  if (session?.inflight) {
    await ctx.reply("‚öÝÔ∏è ÁõÆÂâçÊúâ turn ÈÄ≤Ë°å‰∏≠ÔºåË´ãÁ≠âÂÆÉÂÆåÊàêÊàñÂÖà /cancel ÂÜçÂàáÊèõ„ÄÇ");
    return;
  }

  // exportSession runs the local-LLM handoff summary ‚Äî takes a few seconds.
  await ctx.reply(`üîÑ Ê≠£Âú®‰∫§Êé•Â∞çË©±ËÑàÁµ°‰∏¶ÂàáÊèõÂà∞ ${def.label}‚Ä¶`);
  try {
    await sessions.switchAgent(chatId, arg, userId);
    await ctx.reply(
      `‚úÖ Â∑≤ÂàáÊèõÂà∞ **${def.label}**ÔºàÂâçÊÆµÂ∞çË©±ÊëòË¶ÅÂ∑≤Ê≥®ÂÖ•Êñ∞ sessionÔºâ`,
      { parse_mode: "Markdown" },
    );
  } catch (err) {
    await ctx.reply(`‚ùå ÂàáÊèõÂ§±ÊïóÔºö${(err as Error).message}`);
  }
}

function describeCurrent(activeProvider?: string, acpBackend?: string): string {
  if (!activeProvider) return `(Â∞öÁÑ° session ‚Äî ‰∏ã‰∏ÄÂâáË®äÊÅØÊúÉÁî® .env ÈÝêË®≠ ${config.agent.command} ÈñãÂïü)`;
  if (activeProvider !== "acp") return `Direct API provider \`${activeProvider}\`ÔºàÁî® /model ÁÆ°ÁêÜÔºâ`;
  if (acpBackend) {
    const def = loadAcpProviders()[acpBackend];
    return def ? `**${def.label}**Ôºà\`${acpBackend}\`Ôºâ` : `\`${acpBackend}\`ÔºàË®≠ÂÆöÊ™îÂ∑≤ÁÑ°Ê≠§ÈÝÖÔºâ`;
  }
  return `.env ÈÝêË®≠Ôºà${config.agent.command} ${config.agent.args.join(" ")}Ôºâ`;
}

