async function main() {
  console.log(`Starting Telegram ‚Üî Kiro bridge`);
  console.log(`  agent: ${config.agent.command} ${config.agent.args.join(" ")}`);
  console.log(`  cwd:   ${config.sessionCwd}`);
  console.log(`  PATH:  ${process.env.PATH ?? "(empty)"}`);
  console.log(`  Path:  ${process.env.Path ?? "(empty)"}`);
  console.log(`  PATH===Path: ${process.env.PATH === process.env.Path}`);
  console.log(
    `  auth:  ${
      config.allowedUserIds.length
        ? `restricted to ${config.allowedUserIds.join(", ")}`
        : "open to anyone"
    }`
  );
  // Ensure topics.json exists. Seeds built-in defaults on first run so
  // users can edit it without rebuilding.
  try {
    const { created, file } = bootstrapTopicsFile();
    console.log(
      `  topics: ${file}${created ? " (created from defaults)" : ""} ‚Äî active source: ${topicRulesSource()}`
    );
  } catch (err) {
    console.warn("[topic-rules] bootstrap failed:", err);
  }
